export enum ToolStatus {
  Good = 'Tốt',
  Borrowed = 'Đang mượn',
  Damaged = 'Hỏng',
  Sterilizing = 'Chờ tiệt trùng',
  Liquidated = 'Đã thanh lý'
}

export enum UserRole {
  Admin = 'Admin',
  Manager = 'Quản lý kho',
  Nurse = 'Điều dưỡng/KTV',
  Doctor = 'Bác sĩ',
  Accountant = 'Kế toán'
}

export interface MedicalTool {
  id: string;
  code: string;
  name: string;
  type: string;
  unit: string;
  totalQuantity: number;
  availableQuantity: number;
  status: ToolStatus;
  entryDate: string;
  note?: string;
}

export interface KitItem {
  toolId: string;
  quantity: number;
}

export interface ToolKit {
  id: string;
  code: string;
  name: string;
  items: KitItem[];
}

export interface BorrowItem {
  type: 'tool' | 'kit';
  id: string;
  quantity: number;
  returned: boolean;
  statusOnReturn?: 'Good' | 'Damaged' | 'Missing';
}

export interface BorrowForm {
  id: string;
  borrower: string;
  department: string;
  borrowDate: string;
  returnDate?: string;
  items: BorrowItem[];
  status: 'Active' | 'Returned' | 'Partial';
}

export interface LiquidationRecord {
