import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { MedicalTool, BorrowForm, ToolStatus } from '../types';

interface DashboardProps {
  tools: MedicalTool[];
  borrows: BorrowForm[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#6b7280'];

const StatCard: React.FC<{ label: string; value: number | string; icon: React.ReactNode; color: string }> = ({ label, value, icon, color }) => (
  <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3 rounded-lg ${color} text-white`}>
      {icon}
    </div>
    <div>
      <p className="text-sm text-gray-500 font-medium">{label}</p>
      <p className="text-2xl font-bold text-gray-900">{value}</p>
    </div>
  </div>
);

const Dashboard: React.FC<DashboardProps> = ({ tools, borrows }) => {
  const stats = useMemo(() => {
    const total = tools.length;
    const damaged = tools.filter(t => t.status === ToolStatus.Damaged).length;
    const sterilizing = tools.filter(t => t.status === ToolStatus.Sterilizing).length;
    const activeBorrows = borrows.filter(b => b.status === 'Active').length;

    return { total, damaged, sterilizing, activeBorrows };
  }, [tools, borrows]);

  const chartData = useMemo(() => {
    return tools.slice(0, 5).map(t => ({
      name: t.name,
      total: t.totalQuantity,
      available: t.availableQuantity
    }));
  }, [tools]);

  const statusData = useMemo(() => {
    const statuses = Object.values(ToolStatus);
    return statuses.map(status => ({
      name: status,
      value: tools.filter(t => t.status === status).length
    })).filter(d => d.value > 0);
  }, [tools]);

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Tổng số dụng cụ" value={stats.total} color="bg-blue-600" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>} />
        <StatCard label="Phiếu mượn hoạt động" value={stats.activeBorrows} color="bg-green-600" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>} />
        <StatCard label="Dụng cụ hư hỏng" value={stats.damaged} color="bg-red-600" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>} />
        <StatCard label="Đang tiệt trùng" value={stats.sterilizing} color="bg-amber-600" icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.183.15l-3.083 1.233A2 2 0 00.5 18.415V21a2 2 0 002 2h19a2 2 0 002-2v-2.585a2 2 0 00-1.072-1.788l-3.5-1.4zM12 11a4 4 0 100-8 4 4 0 000 8z" /></svg>} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
          <h3 className="text-lg font-bold mb-6 text-gray-800">Phân bổ tồn kho</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="total" fill="#3b82f6" name="Tổng" radius={[4, 4, 0, 0]} />
                <Bar dataKey="available" fill="#10b981" name="Khả dụng" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
          <h3 className="text-lg font-bold mb-6 text-gray-800">Tình trạng dụng cụ</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={statusData}
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 space-y-2">
            {statusData.map((d, i) => (
              <div key={d.name} className="flex items-center justify-between text-sm">
                <div className="flex items-center space-x-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></div>
                  <span className="text-gray-600">{d.name}</span>
                </div>
                <span className="font-semibold">{d.value}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { MedicalTool, ToolStatus } from '../types';
import { TOOL_TYPES } from '../constants';

interface ToolsListProps {
  tools: MedicalTool[];
  onAddTool: (tool: Partial<MedicalTool>) => void;
  onEditTool: (tool: MedicalTool) => void;
  onLiquidate: (id: string) => void;
}

const ToolsList: React.FC<ToolsListProps> = ({ tools, onAddTool, onEditTool, onLiquidate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('All');

  const filteredTools = tools.filter(t => 
    (filterType === 'All' || t.type === filterType) &&
    (t.name.toLowerCase().includes(searchTerm.toLowerCase()) || t.code.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
      <div className="p-6 border-b border-gray-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex-1 flex items-center space-x-4">
          <div className="relative flex-1 max-w-md">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-400">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </span>
            <input
              type="text"
              placeholder="Tìm kiếm dụng cụ..."
              className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <select 
            className="px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
          >
            <option value="All">Tất cả loại</option>
            {TOOL_TYPES.map(type => <option key={type} value={type}>{type}</option>)}
          </select>
        </div>
        <button 
          onClick={() => onAddTool({})}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center space-x-2"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" /></svg>
          <span>Thêm dụng cụ</span>
        </button>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-gray-50 text-gray-500 text-xs font-semibold uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Mã</th>
              <th className="px-6 py-4">Tên dụng cụ</th>
              <th className="px-6 py-4">Loại</th>
              <th className="px-6 py-4">Số lượng (Tổng/Kho)</th>
              <th className="px-6 py-4">Trạng thái</th>
              <th className="px-6 py-4">Hành động</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {filteredTools.map(tool => (
              <tr key={tool.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 font-medium text-blue-600">{tool.code}</td>
                <td className="px-6 py-4 text-gray-900 font-medium">{tool.name}</td>
                <td className="px-6 py-4 text-gray-500">{tool.type}</td>
                <td className="px-6 py-4">
                  <span className="font-semibold text-gray-900">{tool.totalQuantity}</span>
                  <span className="text-gray-400"> / </span>
                  <span className={`font-semibold ${tool.availableQuantity < 5 ? 'text-red-500' : 'text-green-600'}`}>{tool.availableQuantity}</span>
                </td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${
                    tool.status === ToolStatus.Good ? 'bg-green-100 text-green-700' :
                    tool.status === ToolStatus.Damaged ? 'bg-red-100 text-red-700' :
                    tool.status === ToolStatus.Sterilizing ? 'bg-amber-100 text-amber-700' :
                    'bg-gray-100 text-gray-700'
                  }`}>
                    {tool.status}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center space-x-3">
                    <button onClick={() => onEditTool(tool)} className="text-blue-600 hover:text-blue-800 font-medium text-sm underline">Sửa</button>
