  kits: ToolKit[];
  onClose: () => void;
  onSave: (borrower: string, dept: string, items: BorrowItem[]) => void;
}

const BorrowModal: React.FC<BorrowModalProps> = ({ tools, kits, onClose, onSave }) => {
  const [borrower, setBorrower] = useState('');
  const [dept, setDept] = useState('');
  const [selectedItems, setSelectedItems] = useState<BorrowItem[]>([]);

  const addItem = (id: string, type: 'tool' | 'kit') => {
    const exists = selectedItems.find(i => i.id === id && i.type === type);
    if (exists) {
      setSelectedItems(selectedItems.map(i => i.id === id ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      const name = type === 'tool' ? tools.find(t => t.id === id)?.name : kits.find(k => k.id === id)?.name;
      setSelectedItems([...selectedItems, { id, type, quantity: 1, name: name || '' }]);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
