  };

  const handleLiquidate = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn thanh lý dụng cụ này? Dữ liệu sẽ được cập nhật vào SQL.')) {
      db.liquidateTool(id);
      refreshData();
    }
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <ToolsList 
            tools={tools} 
            onAddTool={() => {
              setEditingTool(null);
              setShowToolModal(true);
            }} 
            onEditTool={(tool) => {
              setEditingTool(tool);
              setShowToolModal(true);
            }} 
            onLiquidate={handleLiquidate} 
          />
        );
      case 'kits':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {kits.map(kit => (
              <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="font-bold text-gray-800">{kit.name}</h3>
                  <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                </div>
                <div className="space-y-3">
                  {kit.items.map(item => {
                    const tool = tools.find(t => t.id === item.toolId);
                    return (
                      <div key={item.toolId} className="flex items-center justify-between text-sm">
                        <span className="text-gray-600">{tool?.name || 'Unknown'}</span>
                        <span className="font-semibold px-2 bg-gray-50 rounded">x{item.quantity}</span>
                      </div>
                    );
                  })}
                </div>
                <div className="mt-6 pt-4 border-t border-gray-50 flex space-x-2">
                  <button onClick={() => setShowBorrowModal(true)} className="flex-1 py-2 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors">Dùng Kit này</button>
                </div>
              </div>
            ))}
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
              <button 
                onClick={() => setShowBorrowModal(true)}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-colors"
              >
                + Tạo phiếu mượn
              </button>
            </div>

            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-gray-50 text-gray-500 text-xs font-semibold uppercase">
                  <tr>
                    <th className="px-6 py-4">Mã Phiếu</th>
                    <th className="px-6 py-4">Người mượn</th>
                    <th className="px-6 py-4">Khoa/Phòng</th>
                    <th className="px-6 py-4">Dụng cụ</th>
                    <th className="px-6 py-4">Ngày mượn</th>
                    <th className="px-6 py-4">Trạng thái</th>
                    <th className="px-6 py-4">Hành động</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {borrows.slice().reverse().map(b => (
                    <tr key={b.id}>
                      <td className="px-6 py-4 font-bold text-blue-600">{b.id}</td>
                      <td className="px-6 py-4 font-medium">{b.borrower}</td>
                      <td className="px-6 py-4 text-gray-500">{b.department}</td>
                      <td className="px-6 py-4">
                        <div className="text-xs space-y-1">
                          {b.items.map((it, i) => (
                            <div key={i} className="text-gray-600">• {it.name} (x{it.quantity})</div>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-xs text-gray-500">{new Date(b.borrowDate).toLocaleString('vi-VN')}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${b.status === 'Active' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-500'}`}>
                          {b.status === 'Active' ? 'Đang mượn' : 'Đã trả'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {b.status === 'Active' && (
                          <button onClick={() => handleReturn(b.id)} className="text-green-600 font-bold hover:underline">Hoàn trả</button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'history':
        return (
          <div className="bg-white p-12 rounded-xl text-center border-2 border-dashed border-gray-100">
            <h3 className="text-xl font-bold text-gray-400 uppercase tracking-widest">Truy vết lịch sử (SQL Logs)</h3>
            <p className="text-gray-400 mt-2 italic">Dữ liệu đang được ghi nhận từ persistence service...</p>
          </div>
        );
      case 'reports':
        return (
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-xl border border-blue-100 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-6 bg-blue-600 rounded-full"></div>
                  <h3 className="text-xl font-bold text-gray-800">Phân tích AI từ dữ liệu SQL</h3>
                </div>
                <button onClick={fetchInsights} className="text-blue-600 hover:text-blue-800 text-sm font-bold flex items-center space-x-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                  <span>Làm mới phân tích</span>
                </button>
              </div>
              {loadingInsights ? (
                <div className="flex items-center space-x-3 text-blue-600 animate-pulse p-4">
                  <div className="w-4 h-4 bg-blue-600 rounded-full"></div>
                  <span>AI đang đọc "SQL Database" và đưa ra dự báo...</span>
                </div>
              ) : (
                <div className="prose max-w-none text-gray-700 whitespace-pre-line bg-blue-50/50 p-6 rounded-lg border border-blue-100">
                  {insights || "Chưa có dữ liệu phân tích."}
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>Trang chưa hoàn thiện</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {renderContent()}
      {showBorrowModal && (
        <BorrowModal 
          tools={tools} 
          kits={kits} 
          onClose={() => setShowBorrowModal(false)} 
          onSave={handleCreateBorrow}
        />
      )}
      {showToolModal && (
        <ToolFormModal 
          tool={editingTool}
          onClose={() => {
            setShowToolModal(false);
            setEditingTool(null);
          }}
          onSave={handleSaveTool}
        />
      )}
    </Layout>
  );
};

export default App;

