export enum ToolStatus {
  Good = 'Tốt',
  Borrowed = 'Đang mượn',
  Damaged = 'Hỏng',
  Sterilizing = 'Chờ tiệt trùng',
  Liquidated = 'Đã thanh lý'
}

export type Role = 'admin' | 'user' | 'viewer';

export interface User {
  id: string;
  username: string;
  fullName: string;
  role: Role;
  email: string;
}

export interface SystemLog {
  id: string;
  timestamp: string;
  userId: string;
  userName: string;
  action: 'ADD' | 'EDIT' | 'ADJUST' | 'BORROW' | 'RETURN' | 'DELETE';
  details: string;
}

export interface MedicalTool {
  id: string;
  code: string;
  name: string;
  type: string;
  unit: string;
  totalQuantity: number;
  availableQuantity: number;
  status: ToolStatus;
  entryDate: string;
  note?: string;
}

export interface KitItem {
  toolId: string;
  quantity: number;
}

export interface ToolKit {
  id: string;
  code: string;
  name: string;
  items: KitItem[];
}

export interface BorrowItem {
  type: 'tool' | 'kit';
  id: string;
  name: string;
  quantity: number;
}

export interface BorrowForm {
  id: string;
  borrower: string;
  department: string;
  borrowDate: string;
  returnDate?: string;
  items: BorrowItem[];
  status: 'Active' | 'Returned';
}

export interface DatabaseSchema {
  tools: MedicalTool[];
  kits: ToolKit[];
  borrows: BorrowForm[];
  logs: SystemLog[];
}

import { MedicalTool, ToolKit, BorrowForm, DatabaseSchema, ToolStatus, SystemLog, User } from '../types';
import { MOCK_TOOLS, MOCK_KITS, MOCK_BORROWS } from './mockData';

const DB_KEY = 'surgitrack_db_v1';

class PersistenceService {
  private data: DatabaseSchema;

  constructor() {
    const saved = localStorage.getItem(DB_KEY);
    if (saved) {
      this.data = JSON.parse(saved);
      if (!this.data.logs) this.data.logs = [];
    } else {
      this.data = {
        tools: MOCK_TOOLS,
        kits: MOCK_KITS,
        borrows: MOCK_BORROWS,
        logs: []
      };
      this.save();
    }
  }

  private save() {
    localStorage.setItem(DB_KEY, JSON.stringify(this.data));
  }

  private addLog(user: User, action: SystemLog['action'], details: string) {
    const log: SystemLog = {
      id: `L-${Date.now()}`,
      timestamp: new Date().toISOString(),
      userId: user.id,
      userName: user.fullName,
      action,
      details
    };
    this.data.logs.unshift(log); // Thêm vào đầu danh sách
    this.save();
  }

  getLogs() { return [...this.data.logs]; }

  // Tools CRUD
  getTools() { return [...this.data.tools]; }

  upsertTool(tool: MedicalTool, user: User) {
    const index = this.data.tools.findIndex(t => t.id === tool.id);
    const isNew = index === -1;
    if (!isNew) {
      this.data.tools[index] = tool;
      this.addLog(user, 'EDIT', `Sửa thông tin dụng cụ: ${tool.name} (${tool.code})`);
    } else {
      this.data.tools.push(tool);
      this.addLog(user, 'ADD', `Thêm mới dụng cụ: ${tool.name} (${tool.code}) - SL: ${tool.totalQuantity}`);
    }
    this.save();
  }

  adjustStock(id: string, delta: number, user: User) {
    const tool = this.data.tools.find(t => t.id === id);
    if (tool) {
      const newTotal = tool.totalQuantity + delta;
      const newAvailable = tool.availableQuantity + delta;

      if (newTotal < 0 || newAvailable < 0) {
        throw new Error("Số lượng không đủ để thực hiện thao tác này");
      }

      const actionLabel = delta > 0 ? "Nhập bổ sung" : "Thanh lý bớt";
      this.addLog(user, 'ADJUST', `${actionLabel} dụng cụ ${tool.name}: ${Math.abs(delta)} ${tool.unit}`);

      tool.totalQuantity = newTotal;
      tool.availableQuantity = newAvailable;

      if (tool.totalQuantity === 0) {
        tool.status = ToolStatus.Liquidated;
      } else if (tool.availableQuantity === 0) {
        tool.status = ToolStatus.Borrowed;
      } else {
        tool.status = ToolStatus.Good;
      }

      this.save();
    }
  }

  // Kits CRUD
  getKits() { return [...this.data.kits]; }

  // Borrow Transaction Logic
  getBorrows() { return [...this.data.borrows]; }

  createBorrow(form: Omit<BorrowForm, 'id'>, user: User): string {
    const newId = `B-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;
    const newForm: BorrowForm = { ...form, id: newId };

    const itemsSummary = form.items.map(i => `${i.name} (x${i.quantity})`).join(', ');
    this.addLog(user, 'BORROW', `Tạo phiếu mượn ${newId} cho ${form.borrower} (${form.department}). Dụng cụ: ${itemsSummary}`);

    for (const item of form.items) {
      if (item.type === 'tool') {
        this.updateToolStock(item.id, item.quantity);
      } else {
        const kit = this.data.kits.find(k => k.id === item.id);
        if (kit) {
          kit.items.forEach(ki => this.updateToolStock(ki.toolId, ki.quantity * item.quantity));
        }
      }
    }

    this.data.borrows.push(newForm);
    this.save();
    return newId;
  }

  private updateToolStock(toolId: string, quantityChange: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (tool) {
      tool.availableQuantity = Math.max(0, tool.availableQuantity - quantityChange);
      if (tool.availableQuantity === 0) tool.status = ToolStatus.Borrowed;
      this.save();
    }
  }

  returnBorrow(id: string, user: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && borrow.status === 'Active') {
      borrow.status = 'Returned';
      borrow.returnDate = new Date().toISOString();

      this.addLog(user, 'RETURN', `Hoàn trả phiếu mượn ${id} từ ${borrow.borrower}`);

      for (const item of borrow.items) {
        if (item.type === 'tool') {
          this.restoreToolStock(item.id, item.quantity);
        } else {
          const kit = this.data.kits.find(k => k.id === item.id);
          if (kit) {
            kit.items.forEach(ki => this.restoreToolStock(ki.toolId, ki.quantity * item.quantity));
          }
        }
      }
      this.save();
    }
  }

  private restoreToolStock(toolId: string, quantity: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (tool) {
      tool.availableQuantity += quantity;
      tool.status = ToolStatus.Good;
      this.save();
    }
  }
}

export const db = new PersistenceService();

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;
    const headers = Object.keys(data[0]).join(',');
    const rows = data.map(obj => Object.values(obj).map(v => `"${v}"`).join(','));
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button 
                onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')}
                className="px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors flex items-center space-x-1"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất CSV</span>
              </button>
            </div>
            <ToolsList 
              tools={tools} 
              onAddTool={() => {
                setEditingTool(null);
                setShowToolModal(true);
              }} 
              onEditTool={(tool) => {
                setEditingTool(tool);
                setShowToolModal(true);
              }} 
              onAdjustStock={handleAdjustStock}
            />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
             <div className="flex justify-end">
              <button 
                onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')}
                className="px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors flex items-center space-x-1"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất DS Gói</span>
              </button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {kits.map(kit => (
                <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-800">{kit.name}</h3>
                    <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                  </div>
                  <div className="space-y-3">
                    {kit.items.map(item => {
                      const tool = tools.find(t => t.id === item.toolId);
                      return (
                        <div key={item.toolId} className="flex items-center justify-between text-sm">
                          <span className="text-gray-600">{tool?.name || 'Unknown'}</span>
                          <span className="font-semibold px-2 bg-gray-50 rounded">x{item.quantity}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-6 pt-4 border-t border-gray-50 flex space-x-2">
                    <button 
                      disabled={currentUser.role === 'viewer'}
                      onClick={() => {
                        // Pre-select kit in borrow modal logic could go here
                        setShowBorrowModal(true);
                      }} 
                      className="flex-1 py-2 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors disabled:opacity-50"
                    >
                      Dùng Kit này
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
