                      </div>
                    ))}
                 </div>
               </div>
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm md:col-span-2">
                  <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Tình trạng phiếu mượn</h4>
                  <div className="flex space-x-8">
                     <div className="flex-1 bg-blue-50 p-4 rounded-lg text-center">
                        <p className="text-blue-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Active').length}</p>
                        <p className="text-blue-500 text-xs font-semibold uppercase mt-1">Đang hoạt động</p>
                     </div>
                     <div className="flex-1 bg-green-50 p-4 rounded-lg text-center">
                        <p className="text-green-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Returned').length}</p>
