import { MedicalTool, ToolKit, BorrowForm, DatabaseSchema, ToolStatus, SystemLog, User } from '../types';
import { MOCK_TOOLS, MOCK_KITS, MOCK_BORROWS } from './mockData';

const DB_KEY = 'surgitrack_db_v1';

class PersistenceService {
  private data: DatabaseSchema;

  constructor() {
    const saved = localStorage.getItem(DB_KEY);
    if (saved) {
      this.data = JSON.parse(saved);
      if (!this.data.logs) this.data.logs = [];
    } else {
      this.data = {
        tools: MOCK_TOOLS,
        kits: MOCK_KITS,
        borrows: MOCK_BORROWS,
        logs: []
      };
      this.save();
    }
  }

  private save() {
    localStorage.setItem(DB_KEY, JSON.stringify(this.data));
  }

  private addLog(user: User, action: SystemLog['action'], details: string) {
    const log: SystemLog = {
      id: `L-${Date.now()}`,
      timestamp: new Date().toISOString(),
      userId: user.id,
      userName: user.fullName,
      action,
      details
    };
    this.data.logs.unshift(log);
    this.save();
  }

  getLogs() { return [...this.data.logs]; }

  // Tools CRUD
  getTools() { return [...this.data.tools]; }

  upsertTool(tool: MedicalTool, user: User) {
    const index = this.data.tools.findIndex(t => t.id === tool.id);
    const isNew = index === -1;
    if (!isNew) {
      this.data.tools[index] = tool;
      this.addLog(user, 'EDIT', `Sửa thông tin dụng cụ: ${tool.name} (${tool.code})`);
    } else {
      this.data.tools.push(tool);
      this.addLog(user, 'ADD', `Thêm mới dụng cụ: ${tool.name} (${tool.code}) - SL: ${tool.totalQuantity}`);
    }
    this.save();
  }

  adjustStock(id: string, delta: number, user: User) {
    const tool = this.data.tools.find(t => t.id === id);
    if (tool) {
      const newTotal = tool.totalQuantity + delta;
      const newAvailable = tool.availableQuantity + delta;

      if (newTotal < 0 || newAvailable < 0) {
        throw new Error("Số lượng không đủ để thực hiện thao tác này");
      }

      const actionLabel = delta > 0 ? "Nhập bổ sung" : "Thanh lý bớt";
      this.addLog(user, 'ADJUST', `${actionLabel} dụng cụ ${tool.name}: ${Math.abs(delta)} ${tool.unit}`);

      tool.totalQuantity = newTotal;
      tool.availableQuantity = newAvailable;

      if (tool.totalQuantity === 0) {
        tool.status = ToolStatus.Liquidated;
      } else if (tool.availableQuantity === 0) {
        tool.status = ToolStatus.Borrowed;
      } else {
        tool.status = ToolStatus.Good;
      }

      this.save();
    }
  }

  // Kits CRUD
  getKits() { return [...this.data.kits]; }

  upsertKit(kit: ToolKit, user: User) {
    const index = this.data.kits.findIndex(k => k.id === kit.id);
    const isNew = index === -1;
    if (!isNew) {
      this.data.kits[index] = kit;
      this.addLog(user, 'EDIT', `Sửa thông tin gói dụng cụ: ${kit.name} (${kit.code})`);
    } else {
      this.data.kits.push(kit);
      this.addLog(user, 'ADD', `Tạo mới gói dụng cụ: ${kit.name} (${kit.code})`);
    }
    this.save();
  }

  // Borrow Transaction Logic
  getBorrows() { return [...this.data.borrows]; }

  createBorrow(form: Omit<BorrowForm, 'id'>, user: User): string {
    const newId = `B-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;
    const newForm: BorrowForm = { ...form, id: newId };

    const itemsSummary = form.items.map(i => `${i.name} (x${i.quantity})`).join(', ');
    this.addLog(user, 'BORROW', `Tạo phiếu mượn ${newId} cho ${form.borrower} (${form.department}). Dụng cụ: ${itemsSummary}`);

    for (const item of form.items) {
      if (item.type === 'tool') {
        this.updateToolStock(item.id, item.quantity);
      } else {
        const kit = this.data.kits.find(k => k.id === item.id);
        if (kit) {
          kit.items.forEach(ki => this.updateToolStock(ki.toolId, ki.quantity * item.quantity));
        }
      }
    }

    this.data.borrows.push(newForm);
    this.save();
    return newId;
  }

  private updateToolStock(toolId: string, quantityChange: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (tool) {
      tool.availableQuantity = Math.max(0, tool.availableQuantity - quantityChange);
      if (tool.availableQuantity === 0) tool.status = ToolStatus.Borrowed;
      this.save();
    }
  }

  returnBorrow(id: string, user: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && borrow.status === 'Active') {
      borrow.status = 'Returned';
      borrow.returnDate = new Date().toISOString();

      this.addLog(user, 'RETURN', `Hoàn trả phiếu mượn ${id} từ ${borrow.borrower}`);

      for (const item of borrow.items) {
        if (item.type === 'tool') {
          this.restoreToolStock(item.id, item.quantity);
        } else {
          const kit = this.data.kits.find(k => k.id === item.id);
          if (kit) {
            kit.items.forEach(ki => this.restoreToolStock(ki.toolId, ki.quantity * item.quantity));
          }
        }
      }
      this.save();
    }
  }

  private restoreToolStock(toolId: string, quantity: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (tool) {
      tool.availableQuantity += quantity;
      tool.status = ToolStatus.Good;
      this.save();
    }
  }
}

export const db = new PersistenceService();

import React, { useState, useEffect } from 'react';
import { ToolKit, MedicalTool, KitItem } from '../types';

interface KitFormModalProps {
  kit?: ToolKit | null;
  tools: MedicalTool[];
  onClose: () => void;
  onSave: (kit: ToolKit) => void;
}

const KitFormModal: React.FC<KitFormModalProps> = ({ kit, tools, onClose, onSave }) => {
  const [name, setName] = useState('');
  const [code, setCode] = useState('');
  const [selectedItems, setSelectedItems] = useState<KitItem[]>([]);
  const [toolSearch, setToolSearch] = useState('');

  useEffect(() => {
    if (kit) {
      setName(kit.name);
      setCode(kit.code);
      setSelectedItems(kit.items);
    }
  }, [kit]);

  const toggleTool = (tool: MedicalTool) => {
    const exists = selectedItems.find(i => i.toolId === tool.id);
    if (exists) {
      setSelectedItems(selectedItems.filter(i => i.toolId !== tool.id));
    } else {
      setSelectedItems([...selectedItems, { toolId: tool.id, quantity: 1 }]);
    }
  };

  const updateQuantity = (toolId: string, qty: number) => {
    setSelectedItems(selectedItems.map(item => 
      item.toolId === toolId ? { ...item, quantity: Math.max(1, qty) } : item
    ));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !code) return alert('Vui lòng nhập tên và mã gói');
    if (selectedItems.length === 0) return alert('Vui lòng chọn ít nhất một dụng cụ');

    const finalKit: ToolKit = {
      id: kit?.id || `K-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      name,
      code,
      items: selectedItems
    };
    onSave(finalKit);
  };

  const filteredTools = tools.filter(t => 
    t.name.toLowerCase().includes(toolSearch.toLowerCase()) || 
    t.code.toLowerCase().includes(toolSearch.toLowerCase())
  );

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <form onSubmit={handleSubmit} className="bg-white rounded-2xl w-full max-w-4xl shadow-2xl flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <h3 className="text-xl font-bold text-gray-800">
            {kit ? 'Chỉnh sửa gói dụng cụ' : 'Thiết lập gói dụng cụ mới'}
          </h3>
          <button type="button" onClick={onClose} className="text-gray-400 hover:text-gray-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="p-6 overflow-hidden flex flex-col md:flex-row gap-6">
          {/* Left Side: General Info & Tool Selection */}
          <div className="flex-1 space-y-4 overflow-y-auto">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Mã gói *</label>
                <input 
                  required
                  value={code} 
                  onChange={e => setCode(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder="SET-001" 
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Tên gói *</label>
                <input 
                  required
                  value={name} 
                  onChange={e => setName(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder="Gói mổ nội soi..." 
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-bold text-gray-800">Chọn dụng cụ vào gói</label>
              <input 
                type="text"
                placeholder="Tìm dụng cụ..."
                className="w-full px-4 py-2 border rounded-lg mb-2 text-sm"
                value={toolSearch}
                onChange={e => setToolSearch(e.target.value)}
              />
              <div className="h-64 overflow-y-auto border rounded-lg divide-y bg-gray-50">
                {filteredTools.map(t => {
                  const isSelected = selectedItems.some(i => i.toolId === t.id);
                  return (
                    <button 
                      key={t.id} 
                      type="button"
                      onClick={() => toggleTool(t)}
                      className={`w-full text-left p-3 flex items-center justify-between transition-colors ${isSelected ? 'bg-blue-50' : 'hover:bg-white'}`}
                    >
                      <div>
                        <p className="text-sm font-medium text-gray-900">{t.name}</p>
                        <p className="text-xs text-gray-400">{t.code} • {t.type}</p>
                      </div>
                      <div className={`w-5 h-5 rounded-full border flex items-center justify-center ${isSelected ? 'bg-blue-600 border-blue-600 text-white' : 'border-gray-300 bg-white'}`}>
                        {isSelected && <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Right Side: Kit Items Preview */}
          <div className="w-full md:w-80 bg-gray-50 rounded-xl p-4 flex flex-col border border-gray-100">
            <h4 className="text-sm font-bold text-gray-700 uppercase mb-4 tracking-wider">Thành phần gói ({selectedItems.length})</h4>
            <div className="flex-1 overflow-y-auto space-y-2 pr-2">
              {selectedItems.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                  <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                  <p className="text-xs font-medium">Chưa có dụng cụ nào</p>
                </div>
              ) : (
                selectedItems.map(item => {
                  const tool = tools.find(t => t.id === item.toolId);
                  return (
                    <div key={item.toolId} className="bg-white p-3 rounded-lg shadow-sm border border-gray-200">
                      <div className="flex justify-between items-start mb-2">
                        <p className="text-sm font-bold text-gray-800 line-clamp-1">{tool?.name}</p>
                        <button type="button" onClick={() => toggleTool(tool!)} className="text-gray-400 hover:text-red-500">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                      </div>
                      <div className="flex items-center space-x-2">
                        <span className="text-xs text-gray-500">SL:</span>
                        <input 
                          type="number"
                          min="1"
                          value={item.quantity}
                          onChange={e => updateQuantity(item.toolId, parseInt(e.target.value) || 1)}
                          className="w-16 px-2 py-1 border rounded text-sm text-center font-bold"
                        />
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>

        <div className="p-6 border-t bg-gray-50 flex justify-end space-x-3">
          <button type="button" onClick={onClose} className="px-6 py-2 text-gray-600 font-medium hover:bg-gray-200 rounded-lg">Hủy</button>
          <button 
            type="submit"
            className="px-8 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 shadow-lg shadow-blue-200"
          >
            {kit ? 'Cập nhật gói' : 'Tạo gói dụng cụ'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default KitFormModal;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import KitFormModal from './components/KitFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  // New state for Kit Management
  const [showKitModal, setShowKitModal] = useState(false);
  const [editingKit, setEditingKit] = useState<ToolKit | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleSaveKit = (kit: ToolKit) => {
    if (!currentUser) return;
    db.upsertKit(kit, currentUser);
    setShowKitModal(false);
    setEditingKit(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;
    const headers = Object.keys(data[0]).join(',');
    const rows = data.map(obj => Object.values(obj).map(v => `"${v}"`).join(','));
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
