        );
      case 'reports':
        const deptStats = borrows.reduce((acc: any, curr) => {
          acc[curr.department] = (acc[curr.department] || 0) + 1;
          return acc;
        }, {});

        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Thống kê theo Khoa</h4>
                 <div className="space-y-3">
                    {Object.entries(deptStats).map(([dept, count]) => (
                      <div key={dept} className="flex justify-between items-center border-b border-gray-50 pb-2">
                        <span className="text-gray-700 font-medium">{dept}</span>
                        <span className="bg-blue-50 text-blue-600 px-2 py-1 rounded text-xs font-bold">{count} lượt mượn</span>
                      </div>
                    ))}
                 </div>
               </div>
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm md:col-span-2">
                  <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Tình trạng phiếu mượn</h4>
                  <div className="flex space-x-8">
                     <div className="flex-1 bg-blue-50 p-4 rounded-lg text-center">
                        <p className="text-blue-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Active').length}</p>
                        <p className="text-blue-500 text-xs font-semibold uppercase mt-1">Đang hoạt động</p>
                     </div>
                     <div className="flex-1 bg-green-50 p-4 rounded-lg text-center">
                        <p className="text-green-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Returned').length}</p>
                        <p className="text-green-500 text-xs font-semibold uppercase mt-1">Đã hoàn trả</p>
                     </div>
                     <div className="flex-1 bg-gray-50 p-4 rounded-lg text-center">
                        <p className="text-gray-600 text-3xl font-bold">{borrows.length}</p>
                        <p className="text-gray-500 text-xs font-semibold uppercase mt-1">Tổng lượt mượn</p>
                     </div>
                  </div>
               </div>
            </div>

            <div className="bg-white p-8 rounded-xl border border-blue-100 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-6 bg-blue-600 rounded-full"></div>
                  <h3 className="text-xl font-bold text-gray-800">Phân tích AI từ dữ liệu SQL</h3>
                </div>
                <button onClick={fetchInsights} className="text-blue-600 hover:text-blue-800 text-sm font-bold flex items-center space-x-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                  <span>Làm mới phân tích</span>
                </button>
              </div>
              {loadingInsights ? (
                <div className="flex items-center space-x-3 text-blue-600 animate-pulse p-4">
                  <div className="w-4 h-4 bg-blue-600 rounded-full"></div>
                  <span>AI đang đọc dữ liệu SQL và đưa ra dự báo...</span>
                </div>
              ) : (
                <div className="prose max-w-none text-gray-700 whitespace-pre-line bg-blue-50/50 p-6 rounded-lg border border-blue-100">
                  {insights || "Chưa có dữ liệu phân tích. Hãy nhấn nút Làm mới."}
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>Trang không khả dụng cho quyền của bạn.</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
      {showBorrowModal && (
        <BorrowModal 
          tools={tools} 
          kits={kits} 
          onClose={() => setShowBorrowModal(false)} 
          onSave={handleCreateBorrow}
        />
      )}
      {showToolModal && (
        <ToolFormModal 
          tool={editingTool}
          onClose={() => {
            setShowToolModal(false);
            setEditingTool(null);
          }}
          onSave={handleSaveTool}
        />
      )}
      {showKitModal && (
        <KitFormModal 
          kit={editingKit}
          tools={tools}
          onClose={() => {
            setShowKitModal(false);
            setEditingKit(null);
          }}
          onSave={handleSaveKit}
        />
      )}
      {showAdjustModal && adjustingTool && (
        <QuantityAdjustmentModal 
          tool={adjustingTool}
          mode={adjustMode}
          onClose={() => {
            setShowAdjustModal(false);
            setAdjustingTool(null);
          }}
          onConfirm={confirmStockAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { MedicalTool, BorrowForm } from "../types";

// Initialize GoogleGenAI using process.env.API_KEY directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates inventory insights using Gemini.
 * Returns a string summary of the inventory status.
 */
export const getInventoryInsights = async (tools: MedicalTool[], borrows: BorrowForm[]): Promise<string> => {
  try {
    const prompt = `
      Analyze the current surgical instrument inventory and usage data.
      Tools: ${JSON.stringify(tools)}
      Active Borrows: ${JSON.stringify(borrows)}

      Provide a concise executive summary focusing on:
      1. Low stock alerts
      2. High demand items
      3. Suggested optimization for surgical kits.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    // Extract text output from response.text getter.
    // Ensure a string is returned even if response.text is undefined.
    return response.text ?? "Could not generate smart insights at this time.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Could not generate smart insights at this time.";
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import KitFormModal from './components/KitFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  // New state for Kit Management
  const [showKitModal, setShowKitModal] = useState(false);
  const [editingKit, setEditingKit] = useState<ToolKit | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleSaveKit = (kit: ToolKit) => {
    if (!currentUser) return;
    db.upsertKit(kit, currentUser);
    setShowKitModal(false);
    setEditingKit(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;
    const headers = Object.keys(data[0]).join(',');
    const rows = data.map(obj => Object.values(obj).map(v => `"${v}"`).join(','));
    const csvContent = "data:text/csv;charset=utf-8," + [headers, ...rows].join('\n');
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    // getInventoryInsights now returns a string explicitly.
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button 
                onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')}
                className="px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors flex items-center space-x-1"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất CSV</span>
              </button>
            </div>
            <ToolsList 
              tools={tools} 
              onAddTool={() => {
                setEditingTool(null);
                setShowToolModal(true);
              }} 
              onEditTool={(tool) => {
                setEditingTool(tool);
                setShowToolModal(true);
              }} 
              onAdjustStock={handleAdjustStock}
            />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Quản lý Gói Dụng cụ</h3>
              <div className="flex space-x-2">
                <button 
                  onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')}
                  className="px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors flex items-center space-x-1"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất DS Gói</span>
                </button>
                {currentUser.role === 'admin' && (
                  <button 
                    onClick={() => {
                      setEditingKit(null);
                      setShowKitModal(true);
                    }}
                    className="px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-colors flex items-center space-x-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    <span>Thêm gói mới</span>
                  </button>
                )}
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {kits.map(kit => (
                <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow group relative">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-800">{kit.name}</h3>
                    <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                  </div>
                  <div className="space-y-3">
                    {kit.items.map(item => {
                      const tool = tools.find(t => t.id === item.toolId);
                      return (
                        <div key={item.toolId} className="flex items-center justify-between text-sm">
                          <span className="text-gray-600">{tool?.name || 'Unknown'}</span>
                          <span className="font-semibold px-2 bg-gray-50 rounded">x{item.quantity}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-6 pt-4 border-t border-gray-50 flex space-x-2">
                    <button 
                      disabled={currentUser.role === 'viewer'}
                      onClick={() => setShowBorrowModal(true)} 
                      className="flex-1 py-2 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors disabled:opacity-50"
                    >
                      Dùng Kit này
                    </button>
                    {currentUser.role === 'admin' && (
                      <button 
                        onClick={() => {
                          setEditingKit(kit);
                          setShowKitModal(true);
                        }}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Sửa cấu hình gói"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2.5 2.5 0 113.536 3.536L12 20.036H3v-3.572L16.732 3.732z" /></svg>
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
              <div className="flex space-x-2">
                 <button 
                  onClick={() => exportToCSV(borrows, 'Bao_cao_muon_tra')}
                  className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg font-bold hover:bg-gray-200 transition-colors flex items-center space-x-2"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất báo cáo</span>
                </button>
                {currentUser.role !== 'viewer' && (
                  <button 
                    onClick={() => setShowBorrowModal(true)}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-colors"
                  >
                    + Tạo phiếu mượn
                  </button>
                )}
              </div>
            </div>

            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-gray-50 text-gray-500 text-xs font-semibold uppercase">
                  <tr>
                    <th className="px-6 py-4">Mã Phiếu</th>
                    <th className="px-6 py-4">Người mượn</th>
                    <th className="px-6 py-4">Khoa/Phòng</th>
                    <th className="px-6 py-4">Dụng cụ</th>
                    <th className="px-6 py-4">Ngày mượn</th>
                    <th className="px-6 py-4">Trạng thái</th>
                    <th className="px-6 py-4">Hành động</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {borrows.slice().reverse().map(b => (
                    <tr key={b.id}>
                      <td className="px-6 py-4 font-bold text-blue-600">{b.id}</td>
                      <td className="px-6 py-4 font-medium">{b.borrower}</td>
                      <td className="px-6 py-4 text-gray-500">{b.department}</td>
                      <td className="px-6 py-4">
                        <div className="text-xs space-y-1">
                          {b.items.map((it, i) => (
                            <div key={i} className="text-gray-600">• {it.name} (x{it.quantity})</div>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-xs text-gray-500">{new Date(b.borrowDate).toLocaleString('vi-VN')}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${b.status === 'Active' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-500'}`}>
                          {b.status === 'Active' ? 'Đang mượn' : 'Đã trả'}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        {b.status === 'Active' && currentUser.role !== 'viewer' && (
                          <button onClick={() => handleReturn(b.id)} className="text-green-600 font-bold hover:underline">Hoàn trả</button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'history':
        return (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Nhật ký hệ thống</h3>
              <button 
                onClick={() => exportToCSV(logs, 'Nhat_ky_he_thong')}
                className="px-3 py-1.5 bg-gray-100 text-gray-700 rounded-lg text-sm font-semibold hover:bg-gray-200 transition-colors"
              >
                Xuất Nhật Ký
              </button>
            </div>
            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
               <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 text-gray-500 text-xs font-semibold uppercase">
                  <tr>
                    <th className="px-6 py-4">Thời gian</th>
                    <th className="px-6 py-4">Người thực hiện</th>
                    <th className="px-6 py-4">Hành động</th>
                    <th className="px-6 py-4">Chi tiết</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {logs.map(log => (
                    <tr key={log.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4 text-gray-500 whitespace-nowrap">
                        {new Date(log.timestamp).toLocaleString('vi-VN')}
                      </td>
                      <td className="px-6 py-4 font-medium text-gray-900">{log.userName}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${
                          log.action === 'ADD' ? 'bg-green-100 text-green-700' :
                          log.action === 'EDIT' ? 'bg-blue-100 text-blue-700' :
                          log.action === 'ADJUST' ? 'bg-purple-100 text-purple-700' :
                          log.action === 'BORROW' ? 'bg-orange-100 text-orange-700' :
                          log.action === 'RETURN' ? 'bg-cyan-100 text-cyan-700' :
                          'bg-gray-100 text-gray-700'
                        }`}>
                          {log.action}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-gray-600">{log.details}</td>
                    </tr>
                  ))}
                  {logs.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-gray-400 italic">Chưa có nhật ký hoạt động nào</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'reports':
        const deptStats = borrows.reduce((acc: any, curr) => {
          acc[curr.department] = (acc[curr.department] || 0) + 1;
          return acc;
        }, {});

        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Thống kê theo Khoa</h4>
                 <div className="space-y-3">
                    {Object.entries(deptStats).map(([dept, count]) => (
                      <div key={dept} className="flex justify-between items-center border-b border-gray-50 pb-2">
                        <span className="text-gray-700 font-medium">{dept}</span>
                        <span className="bg-blue-50 text-blue-600 px-2 py-1 rounded text-xs font-bold">{count} lượt mượn</span>
                      </div>
                    ))}
                 </div>
               </div>
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm md:col-span-2">
                  <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Tình trạng phiếu mượn</h4>
                  <div className="flex space-x-8">
                     <div className="flex-1 bg-blue-50 p-4 rounded-lg text-center">
                        <p className="text-blue-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Active').length}</p>
                        <p className="text-blue-500 text-xs font-semibold uppercase mt-1">Đang hoạt động</p>
                     </div>
                     <div className="flex-1 bg-green-50 p-4 rounded-lg text-center">
                        <p className="text-green-600 text-3xl font-bold">{borrows.filter(b => b.status === 'Returned').length}</p>
                        <p className="text-green-500 text-xs font-semibold uppercase mt-1">Đã hoàn trả</p>
                     </div>
                     <div className="flex-1 bg-gray-50 p-4 rounded-lg text-center">
                        <p className="text-gray-600 text-3xl font-bold">{borrows.length}</p>
                        <p className="text-gray-500 text-xs font-semibold uppercase mt-1">Tổng lượt mượn</p>
                     </div>
                  </div>
               </div>
            </div>

            <div className="bg-white p-8 rounded-xl border border-blue-100 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-6 bg-blue-600 rounded-full"></div>
                  <h3 className="text-xl font-bold text-gray-800">Phân tích AI từ dữ liệu SQL</h3>
                </div>
                <button onClick={fetchInsights} className="text-blue-600 hover:text-blue-800 text-sm font-bold flex items-center space-x-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                  <span>Làm mới phân tích</span>
                </button>
              </div>
              {loadingInsights ? (
                <div className="flex items-center space-x-3 text-blue-600 animate-pulse p-4">
                  <div className="w-4 h-4 bg-blue-600 rounded-full"></div>
                  <span>AI đang đọc dữ liệu SQL và đưa ra dự báo...</span>
                </div>
              ) : (
                <div className="prose max-w-none text-gray-700 whitespace-pre-line bg-blue-50/50 p-6 rounded-lg border border-blue-100">
                  {/* Fixed: insights is a string, and it is correctly typed to avoid 'unknown' errors. */}
                  {insights || "Chưa có dữ liệu phân tích. Hãy nhấn nút Làm mới."}
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>Trang không khả dụng cho quyền của bạn.</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
      {showBorrowModal && (
        <BorrowModal 
          tools={tools} 
          kits={kits} 
          onClose={() => setShowBorrowModal(false)} 
          onSave={handleCreateBorrow}
        />
      )}
      {showToolModal && (
        <ToolFormModal 
          tool={editingTool}
          onClose={() => {
            setShowToolModal(false);
            setEditingTool(null);
          }}
          onSave={handleSaveTool}
        />
      )}
      {showKitModal && (
        <KitFormModal 
          kit={editingKit}
          tools={tools}
          onClose={() => {
            setShowKitModal(false);
            setEditingKit(null);
          }}
          onSave={handleSaveKit}
        />
      )}
      {showAdjustModal && adjustingTool && (
        <QuantityAdjustmentModal 
          tool={adjustingTool}
          mode={adjustMode}
          onClose={() => {
            setShowAdjustModal(false);
            setAdjustingTool(null);
          }}
          onConfirm={confirmStockAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import KitFormModal from './components/KitFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  const [showKitModal, setShowKitModal] = useState(false);
  const [editingKit, setEditingKit] = useState<ToolKit | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleSaveKit = (kit: ToolKit) => {
    if (!currentUser) return;
    db.upsertKit(kit, currentUser);
    setShowKitModal(false);
    setEditingKit(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  // Nâng cấp xuất CSV hỗ trợ Excel Vietnamese (UTF-8 BOM)
  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;

    // Lấy tiêu đề từ keys của object đầu tiên
    const headers = Object.keys(data[0]);
    const headerRow = headers.join(',');

    const rows = data.map(obj => {
      return headers.map(header => {
        let val = obj[header];
        if (val === null || val === undefined) val = "";

        // Nếu là mảng/object (như danh sách items), biến đổi thành chuỗi thân thiện
        if (typeof val === 'object') {
          val = JSON.stringify(val).replace(/"/g, '""');
        } else {
          val = String(val).replace(/"/g, '""');
        }

        return `"${val}"`;
      }).join(',');
    });

    // Thêm BOM (\uFEFF) để Excel mở đúng định dạng UTF-8 (tiếng Việt)
    const csvContent = "\uFEFF" + [headerRow, ...rows].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button 
                onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')}
                className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất Excel</span>
              </button>
            </div>
            <ToolsList 
              tools={tools} 
              onAddTool={() => {
                setEditingTool(null);
                setShowToolModal(true);
              }} 
              onEditTool={(tool) => {
                setEditingTool(tool);
                setShowToolModal(true);
              }} 
              onAdjustStock={handleAdjustStock}
            />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Quản lý Gói Dụng cụ</h3>
              <div className="flex space-x-2">
                <button 
                  onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')}
                  className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất Excel</span>
                </button>
                {currentUser.role === 'admin' && (
                  <button 
                    onClick={() => {
                      setEditingKit(null);
                      setShowKitModal(true);
                    }}
                    className="px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-colors flex items-center space-x-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    <span>Thêm gói mới</span>
                  </button>
                )}
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {kits.map(kit => (
                <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow group relative">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-800">{kit.name}</h3>
                    <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                  </div>
                  <div className="space-y-3">
                    {kit.items.map(item => {
                      const tool = tools.find(t => t.id === item.toolId);
                      return (
                        <div key={item.toolId} className="flex items-center justify-between text-sm">
                          <span className="text-gray-600">{tool?.name || 'Unknown'}</span>
                          <span className="font-semibold px-2 bg-gray-50 rounded">x{item.quantity}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-6 pt-4 border-t border-gray-50 flex space-x-2">
                    <button 
                      disabled={currentUser.role === 'viewer'}
                      onClick={() => setShowBorrowModal(true)} 
                      className="flex-1 py-2 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors disabled:opacity-50"
                    >
                      Dùng Kit này
                    </button>
                    {currentUser.role === 'admin' && (
                      <button 
                        onClick={() => {
                          setEditingKit(kit);
                          setShowKitModal(true);
                        }}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Sửa cấu hình gói"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2.5 2.5 0 113.536 3.536L12 20.036H3v-3.572L16.732 3.732z" /></svg>
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
              <div className="flex space-x-2">
                 <button 
                  onClick={() => exportToCSV(borrows, 'Bao_cao_muon_tra')}
                  className="px-4 py-2 bg-green-50 text-green-700 rounded-lg font-bold hover:bg-green-100 transition-colors flex items-center space-x-2 border border-green-200"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất Excel</span>
                </button>
                {currentUser.role !== 'viewer' && (
                  <button 
                    onClick={() => setShowBorrowModal(true)}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-colors"
                  >
                    + Tạo phiếu mượn
                  </button>
                )}
              </div>
            </div>

            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-gray-50 text-gray-500 text-xs font-semibold uppercase">
                  <tr>
                    <th className="px-6 py-4">Mã Phiếu</th>
                    <th className="px-6 py-4">Người mượn</th>
                    <th className="px-6 py-4">Khoa/Phòng</th>
                    <th className="px-6 py-4">Dụng cụ</th>
                    <th className="px-6 py-4">Ngày mượn</th>
                    <th className="px-6 py-4">Trạng thái</th>
                    <th className="px-6 py-4">Hành động</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-100">
                  {borrows.slice().reverse().map(b => (
                    <tr key={b.id}>
                      <td className="px-6 py-4 font-bold text-blue-600">{b.id}</td>
                      <td className="px-6 py-4 font-medium">{b.borrower}</td>
                      <td className="px-6 py-4 text-gray-500">{b.department}</td>
                      <td className="px-6 py-4">
                        <div className="text-xs space-y-1">
                          {b.items.map((it, i) => (
                            <div key={i} className="text-gray-600">• {it.name} (x{it.quantity})</div>
                          ))}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-xs text-gray-500">{new Date(b.borrowDate).toLocaleString('vi-VN')}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-full text-xs font-bold ${b.status === 'Active' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-500'}`}>
