                          log.action === 'ADJUST' ? 'bg-purple-100 text-purple-700' :
                          log.action === 'BORROW' ? 'bg-orange-100 text-orange-700' :
                          log.action === 'RETURN' ? 'bg-cyan-100 text-cyan-700' :
                          'bg-gray-100 text-gray-700'
                        }`}>
                          {log.action}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-gray-600">{log.details}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'reports':
        const deptStats = borrows.reduce((acc: any, curr) => {
          acc[curr.department] = (acc[curr.department] || 0) + 1;
          return acc;
        }, {});

        return (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
               {/* Thống kê nhanh */}
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h4 className="text-sm font-bold text-gray-500 uppercase mb-4">Thống kê theo Khoa</h4>
                 <div className="space-y-3">
                    {Object.entries(deptStats).map(([dept, count]) => (
                      <div key={dept} className="flex justify-between items-center border-b border-gray-50 pb-2">
                        <span className="text-gray-700 font-medium">{dept}</span>
                        <span className="bg-blue-50 text-blue-600 px-2 py-1 rounded text-xs font-bold">{count} lượt</span>
                      </div>
                    ))}
                 </div>
               </div>

               {/* Trung tâm xuất file Excel */}
               <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm md:col-span-2">
                  <div className="flex items-center justify-between mb-6">
                    <h4 className="text-sm font-bold text-gray-800 uppercase tracking-wider">Trung tâm xuất báo cáo Excel</h4>
                    <span className="text-[10px] bg-green-100 text-green-700 px-2 py-1 rounded font-bold">Tối ưu cho Microsoft Excel</span>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <button onClick={() => exportToCSV(tools, 'Bao_cao_ton_kho')} className="flex items-center p-4 border rounded-xl hover:bg-green-50 transition-colors border-gray-100 group">
                      <div className="w-10 h-10 bg-green-100 text-green-600 rounded-lg flex items-center justify-center mr-3 group-hover:scale-110 transition-transform">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                      </div>
                      <div className="text-left">
                        <p className="text-sm font-bold text-gray-800">Báo cáo tồn kho</p>
                        <p className="text-[10px] text-gray-500">Chi tiết số lượng, mã, loại dụng cụ</p>
                      </div>
                    </button>
                    <button onClick={() => exportToCSV(borrows, 'Lich_su_muon_tra')} className="flex items-center p-4 border rounded-xl hover:bg-green-50 transition-colors border-gray-100 group">
                      <div className="w-10 h-10 bg-green-100 text-green-600 rounded-lg flex items-center justify-center mr-3 group-hover:scale-110 transition-transform">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4" /></svg>
                      </div>
                      <div className="text-left">
                        <p className="text-sm font-bold text-gray-800">Lịch sử mượn trả</p>
                        <p className="text-[10px] text-gray-500">Truy vết người mượn, khoa phòng</p>
                      </div>
                    </button>
                    <button onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')} className="flex items-center p-4 border rounded-xl hover:bg-green-50 transition-colors border-gray-100 group">
                      <div className="w-10 h-10 bg-green-100 text-green-600 rounded-lg flex items-center justify-center mr-3 group-hover:scale-110 transition-transform">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
                      </div>
                      <div className="text-left">
                        <p className="text-sm font-bold text-gray-800">Danh mục gói</p>
                        <p className="text-[10px] text-gray-500">Cấu hình các bộ dụng cụ phẫu thuật</p>
                      </div>
                    </button>
                    <button onClick={() => exportToCSV(logs, 'Nhat_ky_audit')} className="flex items-center p-4 border rounded-xl hover:bg-green-50 transition-colors border-gray-100 group">
                      <div className="w-10 h-10 bg-green-100 text-green-600 rounded-lg flex items-center justify-center mr-3 group-hover:scale-110 transition-transform">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      </div>
                      <div className="text-left">
                        <p className="text-sm font-bold text-gray-800">Nhật ký hệ thống</p>
                        <p className="text-[10px] text-gray-500">Lịch sử thao tác của người dùng</p>
                      </div>
                    </button>
                  </div>
               </div>
            </div>

            <div className="bg-white p-8 rounded-xl border border-blue-100 shadow-sm">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center space-x-2">
                  <div className="w-2 h-6 bg-blue-600 rounded-full"></div>
                  <h3 className="text-xl font-bold text-gray-800">Phân tích thông minh (AI)</h3>
                </div>
                <button onClick={fetchInsights} className="text-blue-600 hover:text-blue-800 text-sm font-bold flex items-center space-x-1">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                  <span>Làm mới phân tích</span>
                </button>
              </div>
              {loadingInsights ? (
                <div className="flex items-center space-x-3 text-blue-600 animate-pulse p-4">
                  <div className="w-4 h-4 bg-blue-600 rounded-full"></div>
                  <span>AI đang tổng hợp dữ liệu để đưa ra dự báo...</span>
                </div>
              ) : (
                <div className="prose max-w-none text-gray-700 whitespace-pre-line bg-blue-50/50 p-6 rounded-lg border border-blue-100">
                  {insights || "Chưa có dữ liệu phân tích. Hãy nhấn nút Làm mới."}
                </div>
              )}
            </div>
          </div>
        );
      default:
        return <div>Trang không khả dụng cho quyền của bạn.</div>;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
      {showBorrowModal && (
        <BorrowModal 
          tools={tools} 
          kits={kits} 
          onClose={() => setShowBorrowModal(false)} 
          onSave={handleCreateBorrow}
        />
      )}
      {showToolModal && (
        <ToolFormModal 
          tool={editingTool}
          onClose={() => {
            setShowToolModal(false);
            setEditingTool(null);
          }}
          onSave={handleSaveTool}
        />
      )}
      {showKitModal && (
        <KitFormModal 
          kit={editingKit}
          tools={tools}
          onClose={() => {
            setShowKitModal(false);
            setEditingKit(null);
          }}
          onSave={handleSaveKit}
        />
      )}
      {showAdjustModal && adjustingTool && (
        <QuantityAdjustmentModal 
          tool={adjustingTool}
          mode={adjustMode}
          onClose={() => {
            setShowAdjustModal(false);
            setAdjustingTool(null);
          }}
          onConfirm={confirmStockAdjustment}
        />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import KitFormModal from './components/KitFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  const [showKitModal, setShowKitModal] = useState(false);
  const [editingKit, setEditingKit] = useState<ToolKit | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleSaveKit = (kit: ToolKit) => {
    if (!currentUser) return;
    db.upsertKit(kit, currentUser);
    setShowKitModal(false);
    setEditingKit(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  // Nâng cấp xuất CSV hỗ trợ Excel Vietnamese (UTF-8 BOM)
  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;

    // Lấy tiêu đề từ keys của object đầu tiên
    const headers = Object.keys(data[0]);
    const headerRow = headers.join(',');

    const rows = data.map(obj => {
      return headers.map(header => {
        let val = obj[header];
        if (val === null || val === undefined) val = "";

        // Nếu là mảng/object (như danh sách items), biến đổi thành chuỗi thân thiện
        if (typeof val === 'object') {
          val = JSON.stringify(val).replace(/"/g, '""');
        } else {
          val = String(val).replace(/"/g, '""');
        }

        return `"${val}"`;
      }).join(',');
    });

    // Thêm BOM (\uFEFF) để Excel mở đúng định dạng UTF-8 (tiếng Việt)
    const csvContent = "\uFEFF" + [headerRow, ...rows].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button 
                onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')}
                className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất Excel</span>
              </button>
            </div>
            <ToolsList 
              tools={tools} 
              onAddTool={() => {
                setEditingTool(null);
                setShowToolModal(true);
              }} 
              onEditTool={(tool) => {
                setEditingTool(tool);
                setShowToolModal(true);
              }} 
              onAdjustStock={handleAdjustStock}
            />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Quản lý Gói Dụng cụ</h3>
              <div className="flex space-x-2">
                <button 
                  onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')}
                  className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất Excel</span>
                </button>
                {currentUser.role === 'admin' && (
                  <button 
                    onClick={() => {
                      setEditingKit(null);
                      setShowKitModal(true);
                    }}
                    className="px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-colors flex items-center space-x-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
