export enum ToolStatus {
  Good = 'Tốt',
  Borrowed = 'Đang mượn',
  Damaged = 'Hỏng',
  Sterilizing = 'Chờ tiệt trùng',
  Liquidated = 'Đã thanh lý'
}

export type Role = 'admin' | 'user' | 'viewer';

export interface User {
  id: string;
  username: string;
  fullName: string;
  role: Role;
  email: string;
  department?: string; // Bổ sung Khoa/Phòng công tác
}

export interface SystemLog {
  id: string;
  timestamp: string;
  userId: string;
  userName: string;
  action: 'ADD' | 'EDIT' | 'ADJUST' | 'BORROW' | 'RETURN' | 'DELETE';
  details: string;
}

export interface MedicalTool {
  id: string;
  code: string;
  name: string;
  type: string;
  unit: string;
  totalQuantity: number;
  availableQuantity: number;
  status: ToolStatus;
  entryDate: string;
  note?: string;
}

export interface KitItem {
  toolId: string;
  quantity: number;
}

export interface ToolKit {
  id: string;
  code: string;
  name: string;
  items: KitItem[];
}

export interface BorrowItem {
  type: 'tool' | 'kit';
  id: string;
  name: string;
  quantity: number;
}

export interface BorrowForm {
  id: string;
  borrower: string;
  department: string;
  borrowDate: string;
  returnDate?: string;
  items: BorrowItem[];
  status: 'Active' | 'Returned';
}

export interface DatabaseSchema {
  tools: MedicalTool[];
  kits: ToolKit[];
  borrows: BorrowForm[];
  logs: SystemLog[];
}

