const MOCK_USERS: Record<string, any> = {
  admin: { username: 'admin', password: 'admin', fullName: 'Quản trị hệ thống', role: 'admin', email: 'admin@hospital.com', department: 'Quản lý Tổng hợp' },
  user: { username: 'user', password: '123', fullName: 'ĐD. Nguyễn Thị Mai', role: 'user', email: 'mai.nt@hospital.com', department: 'Ngoại Tổng Quát' },
  user2: { username: 'user2', password: '123', fullName: 'ĐD. Trần Văn Bình', role: 'user', email: 'binh.tv@hospital.com', department: 'Chấn thương chỉnh hình' },
