import React, { useState, useEffect } from 'react';
import { MedicalTool, ToolKit, BorrowItem, User } from '../types';
import { DEPARTMENTS } from '../constants';

interface BorrowModalProps {
  tools: MedicalTool[];
  kits: ToolKit[];
  currentUser: User; // Thêm currentUser để tự động điền
  onClose: () => void;
  onSave: (borrower: string, dept: string, items: BorrowItem[]) => void;
}

const BorrowModal: React.FC<BorrowModalProps> = ({ tools, kits, currentUser, onClose, onSave }) => {
  const [borrower, setBorrower] = useState(currentUser.fullName);
  const [dept, setDept] = useState(currentUser.department || DEPARTMENTS[0]);
  const [selectedItems, setSelectedItems] = useState<BorrowItem[]>([]);

  // Khi modal mở, nếu là user bình thường thì tự động set thông tin của họ
  useEffect(() => {
    if (currentUser.role === 'user') {
      setBorrower(currentUser.fullName);
      setDept(currentUser.department || DEPARTMENTS[0]);
    }
  }, [currentUser]);

  const addItem = (id: string, type: 'tool' | 'kit') => {
    const exists = selectedItems.find(i => i.id === id && i.type === type);
    if (exists) {
      setSelectedItems(selectedItems.map(i => (i.id === id && i.type === type) ? { ...i, quantity: i.quantity + 1 } : i));
    } else {
      const name = type === 'tool' ? tools.find(t => t.id === id)?.name : kits.find(k => k.id === id)?.name;
      setSelectedItems([...selectedItems, { id, type, quantity: 1, name: name || '' }]);
    }
  };

  const removeItem = (idx: number) => {
    setSelectedItems(selectedItems.filter((_, i) => i !== idx));
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
