              />
            </div>
            <div>
              <label className="block text-xs font-bold text-blue-600 uppercase mb-1 tracking-wider">Khoa/Phòng nhận</label>
              <select 
                value={dept} 
                onChange={e => setDept(e.target.value)} 
                className="w-full px-4 py-2 border border-blue-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
              >
                {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="block text-sm font-bold text-gray-800">Chọn Gói/Dụng cụ</label>
              <div className="h-64 overflow-y-auto border rounded-lg divide-y bg-gray-50">
                <div className="p-2 bg-gray-100 text-[10px] font-bold text-gray-500 uppercase">Gói dụng cụ (Kits)</div>
                {kits.map(k => (
                  <button key={k.id} onClick={() => addItem(k.id, 'kit')} className="w-full text-left p-3 hover:bg-white flex justify-between group">
                    <span className="text-sm font-medium text-gray-700">{k.name}</span>
                    <span className="text-blue-600 font-bold opacity-0 group-hover:opacity-100 transition-opacity">+ Thêm</span>
                  </button>
                ))}
                <div className="p-2 bg-gray-100 text-[10px] font-bold text-gray-500 uppercase">Dụng cụ lẻ</div>
                {tools.filter(t => t.availableQuantity > 0).map(t => (
                  <button key={t.id} onClick={() => addItem(t.id, 'tool')} className="w-full text-left p-3 hover:bg-white flex justify-between group">
                    <div className="flex flex-col">
                      <span className="text-sm font-medium text-gray-700">{t.name}</span>
                      <span className="text-[10px] text-gray-400">Kho hiện có: {t.availableQuantity}</span>
                    </div>
                    <span className="text-blue-600 font-bold opacity-0 group-hover:opacity-100 transition-opacity">+ Thêm</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-bold text-gray-800 flex justify-between">
                <span>Danh sách mượn</span>
                {selectedItems.length > 0 && (
                  <span className="text-xs font-normal text-gray-400">{selectedItems.length} mục đã chọn</span>
                )}
              </label>
              <div className="h-64 overflow-y-auto border rounded-lg p-3 space-y-2 bg-white">
                {selectedItems.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-60">
                    <svg className="w-12 h-12 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" /></svg>
                    <p className="text-xs">Chưa có dụng cụ nào</p>
                  </div>
                ) : (
                  selectedItems.map((item, idx) => (
                    <div key={`${item.id}-${idx}`} className="flex items-center justify-between bg-blue-50 p-2 rounded-lg border border-blue-100">
                      <div className="flex flex-col min-w-0 flex-1 mr-2">
                        <span className="text-xs font-bold text-gray-800 truncate">{item.name}</span>
                        <span className="text-[9px] text-blue-600 font-bold uppercase">{item.type === 'kit' ? 'Gói' : 'Dụng cụ'}</span>
                      </div>
                      <div className="flex items-center space-x-2">
                        <input 
                          type="number" 
                          min="1"
                          value={item.quantity} 
                          onChange={e => setSelectedItems(selectedItems.map((it, i) => i === idx ? {...it, quantity: parseInt(e.target.value) || 1} : it))}
                          className="w-12 text-center text-sm border rounded p-1 font-bold"
                        />
                        <button onClick={() => removeItem(idx)} className="text-red-400 hover:text-red-600">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 border-t bg-gray-50 flex justify-end space-x-3">
          <button onClick={onClose} className="px-6 py-2 text-gray-600 font-medium hover:bg-gray-200 rounded-lg">Hủy</button>
          <button 
            disabled={!borrower || selectedItems.length === 0}
            onClick={() => onSave(borrower, dept, selectedItems)}
            className="px-8 py-2 bg-blue-600 text-white font-bold rounded-lg hover:bg-blue-700 disabled:opacity-50 shadow-lg shadow-blue-100"
          >
            Xác nhận Mượn
          </button>
        </div>
      </div>
    </div>
  );
};

export default BorrowModal;

import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import ToolsList from './components/ToolsList';
import BorrowModal from './components/BorrowModal';
import ToolFormModal from './components/ToolFormModal';
import KitFormModal from './components/KitFormModal';
import QuantityAdjustmentModal from './components/QuantityAdjustmentModal';
import Login from './components/Login';
import { MedicalTool, BorrowForm, ToolKit, BorrowItem, User, SystemLog } from './types';
import { db } from './services/persistence';
import { getInventoryInsights } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('surgitrack_session');
    return saved ? JSON.parse(saved) : null;
  });

  const [activeTab, setActiveTab] = useState('dashboard');
  const [tools, setTools] = useState<MedicalTool[]>(db.getTools());
  const [borrows, setBorrows] = useState<BorrowForm[]>(db.getBorrows());
  const [kits, setKits] = useState<ToolKit[]>(db.getKits());
  const [logs, setLogs] = useState<SystemLog[]>(db.getLogs());

  const [showBorrowModal, setShowBorrowModal] = useState(false);
  const [showToolModal, setShowToolModal] = useState(false);
  const [editingTool, setEditingTool] = useState<MedicalTool | null>(null);

  const [showKitModal, setShowKitModal] = useState(false);
  const [editingKit, setEditingKit] = useState<ToolKit | null>(null);

  const [showAdjustModal, setShowAdjustModal] = useState(false);
  const [adjustingTool, setAdjustingTool] = useState<MedicalTool | null>(null);
  const [adjustMode, setAdjustMode] = useState<'restock' | 'liquidate'>('restock');

  const [insights, setInsights] = useState<string>('');
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    if (currentUser) {
      if (currentUser.role === 'user') setActiveTab('borrow');
      else if (currentUser.role === 'viewer') setActiveTab('dashboard');
      else setActiveTab('dashboard');
    }
  }, [currentUser]);

  const refreshData = () => {
    setTools(db.getTools());
    setBorrows(db.getBorrows());
    setKits(db.getKits());
    setLogs(db.getLogs());
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('surgitrack_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('surgitrack_session');
  };

  const handleCreateBorrow = (borrower: string, dept: string, items: BorrowItem[]) => {
    if (!currentUser) return;
    db.createBorrow({
      borrower,
      department: dept,
      items,
      borrowDate: new Date().toISOString(),
      status: 'Active'
    }, currentUser);
    setShowBorrowModal(false);
    refreshData();
  };

  const handleSaveTool = (tool: MedicalTool) => {
    if (!currentUser) return;
    db.upsertTool(tool, currentUser);
    setShowToolModal(false);
    setEditingTool(null);
    refreshData();
  };

  const handleSaveKit = (kit: ToolKit) => {
    if (!currentUser) return;
    db.upsertKit(kit, currentUser);
    setShowKitModal(false);
    setEditingKit(null);
    refreshData();
  };

  const handleAdjustStock = (tool: MedicalTool, mode: 'restock' | 'liquidate') => {
    setAdjustingTool(tool);
    setAdjustMode(mode);
    setShowAdjustModal(true);
  };

  const confirmStockAdjustment = (amount: number) => {
    if (adjustingTool && currentUser) {
      try {
        db.adjustStock(adjustingTool.id, amount, currentUser);
        setShowAdjustModal(false);
        setAdjustingTool(null);
        refreshData();
      } catch (err: any) {
        alert(err.message);
      }
    }
  };

  const handleReturn = (id: string) => {
    if (!currentUser) return;
    if (confirm('Xác nhận hoàn trả toàn bộ dụng cụ trong phiếu này?')) {
      db.returnBorrow(id, currentUser);
      refreshData();
    }
  };

  const exportToCSV = (data: any[], filename: string) => {
    if (data.length === 0) return;

    const headers = Object.keys(data[0]);
    const headerRow = headers.join(',');

    const rows = data.map(obj => {
      return headers.map(header => {
        let val = obj[header];
        if (val === null || val === undefined) val = "";
        if (typeof val === 'object') {
          val = JSON.stringify(val).replace(/"/g, '""');
        } else {
          val = String(val).replace(/"/g, '""');
        }
        return `"${val}"`;
      }).join(',');
    });

    const csvContent = "\uFEFF" + [headerRow, ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const fetchInsights = useCallback(async () => {
    if (!process.env.API_KEY) return;
    setLoadingInsights(true);
    const result = await getInventoryInsights(tools, borrows);
    setInsights(result);
    setLoadingInsights(false);
  }, [tools, borrows]);

  useEffect(() => {
    if (activeTab === 'reports') fetchInsights();
  }, [activeTab, fetchInsights]);

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button 
                onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')}
                className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                <span>Xuất Excel</span>
              </button>
            </div>
            <ToolsList 
              tools={tools} 
              onAddTool={() => {
                setEditingTool(null);
                setShowToolModal(true);
              }} 
              onEditTool={(tool) => {
                setEditingTool(tool);
                setShowToolModal(true);
              }} 
              onAdjustStock={handleAdjustStock}
            />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Quản lý Gói Dụng cụ</h3>
              <div className="flex space-x-2">
                <button 
                  onClick={() => exportToCSV(kits, 'Danh_sach_goi_dung_cu')}
                  className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold hover:bg-green-100 transition-colors flex items-center space-x-1 border border-green-200"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất Excel</span>
                </button>
                {currentUser.role === 'admin' && (
                  <button 
                    onClick={() => {
                      setEditingKit(null);
                      setShowKitModal(true);
                    }}
                    className="px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-colors flex items-center space-x-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    <span>Thêm gói mới</span>
                  </button>
                )}
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {kits.map(kit => (
                <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow group relative">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-gray-800">{kit.name}</h3>
                    <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                  </div>
                  <div className="space-y-3">
                    {kit.items.map(item => {
                      const tool = tools.find(t => t.id === item.toolId);
                      return (
                        <div key={item.toolId} className="flex items-center justify-between text-sm">
                          <span className="text-gray-600">{tool?.name || 'Unknown'}</span>
                          <span className="font-semibold px-2 bg-gray-50 rounded">x{item.quantity}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div className="mt-6 pt-4 border-t border-gray-50 flex space-x-2">
                    <button 
                      disabled={currentUser.role === 'viewer'}
                      onClick={() => setShowBorrowModal(true)} 
                      className="flex-1 py-2 text-sm font-semibold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors disabled:opacity-50"
                    >
                      Dùng Kit này
                    </button>
                    {currentUser.role === 'admin' && (
                      <button 
                        onClick={() => {
                          setEditingKit(kit);
                          setShowKitModal(true);
                        }}
                        className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Sửa cấu hình gói"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2.5 2.5 0 113.536 3.536L12 20.036H3v-3.572L16.732 3.732z" /></svg>
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
              <div className="flex space-x-2">
                 <button 
                  onClick={() => exportToCSV(borrows, 'Bao_cao_muon_tra')}
                  className="px-4 py-2 bg-green-50 text-green-700 rounded-lg font-bold hover:bg-green-100 transition-colors flex items-center space-x-2 border border-green-200"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  <span>Xuất Excel</span>
                </button>
                {currentUser.role !== 'viewer' && (
