                {insights || "Dữ liệu AI đang được xử lý..."}
              </div>
            </div>
          </div>
        );
      default: return null;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} user={currentUser!} onLogout={handleLogout}>
      {renderContent()}
      {showBorrowModal && currentUser && (
        <BorrowModal tools={tools} kits={kits} currentUser={currentUser} onClose={() => setShowBorrowModal(false)} onSave={handleRequestBorrow} />
      )}
      {showToolModal && (
        <ToolFormModal tool={editingTool} onClose={() => { setShowToolModal(false); setEditingTool(null); }} onSave={(tool) => { db.upsertTool(tool, currentUser!); refreshData(); setShowToolModal(false); }} />
