import { MedicalTool, ToolKit, BorrowForm, DatabaseSchema, ToolStatus, SystemLog, User, BorrowStatus } from '../types';
import { MOCK_TOOLS, MOCK_KITS, MOCK_BORROWS } from './mockData';

const DB_KEY = 'surgitrack_db_v1';

class PersistenceService {
  private data: DatabaseSchema;

  constructor() {
    const saved = localStorage.getItem(DB_KEY);
    if (saved) {
      this.data = JSON.parse(saved);
      if (!this.data.logs) this.data.logs = [];
    } else {
      // Chuyển đổi dữ liệu mock sang trạng thái mới nếu cần
      this.data = {
        tools: MOCK_TOOLS,
        kits: MOCK_KITS,
        // Fix: Use MOCK_BORROWS directly as it now contains the mandatory requestDate
        borrows: MOCK_BORROWS,
        logs: []
      };
      this.save();
    }
  }

  private save() {
    localStorage.setItem(DB_KEY, JSON.stringify(this.data));
  }

  private addLog(user: User, action: SystemLog['action'], details: string) {
    const log: SystemLog = {
      id: `L-${Date.now()}`,
      timestamp: new Date().toISOString(),
      userId: user.id,
      userName: user.fullName,
      action,
      details
    };
    this.data.logs.unshift(log);
    this.save();
  }

  getLogs() { return [...this.data.logs]; }
  getTools() { return [...this.data.tools]; }
  getKits() { return [...this.data.kits]; }
  getBorrows() { return [...this.data.borrows]; }

  upsertTool(tool: MedicalTool, user: User) {
    const index = this.data.tools.findIndex(t => t.id === tool.id);
    if (index !== -1) {
      this.data.tools[index] = tool;
      this.addLog(user, 'EDIT', `Sửa dụng cụ: ${tool.name}`);
    } else {
      this.data.tools.push(tool);
      this.addLog(user, 'ADD', `Thêm dụng cụ: ${tool.name}`);
    }
    this.save();
  }

  adjustStock(id: string, delta: number, user: User) {
    const tool = this.data.tools.find(t => t.id === id);
    if (tool) {
      tool.totalQuantity += delta;
      tool.availableQuantity += delta;
      tool.status = tool.availableQuantity > 0 ? ToolStatus.Good : ToolStatus.Borrowed;
      this.addLog(user, 'ADJUST', `Điều chỉnh kho ${tool.name}: ${delta}`);
      this.save();
    }
  }

  upsertKit(kit: ToolKit, user: User) {
    const index = this.data.kits.findIndex(k => k.id === kit.id);
    if (index !== -1) {
      this.data.kits[index] = kit;
      this.addLog(user, 'EDIT', `Sửa gói: ${kit.name}`);
    } else {
      this.data.kits.push(kit);
      this.addLog(user, 'ADD', `Tạo gói: ${kit.name}`);
    }
    this.save();
  }

  // Quy trình mới: User gửi yêu cầu mượn
  requestBorrow(form: Omit<BorrowForm, 'id' | 'status' | 'requestDate'>, user: User) {
    const newId = `REQ-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
    const newForm: BorrowForm = {
      ...form,
      id: newId,
      status: 'Requested',
      requestDate: new Date().toISOString()
    };
    this.data.borrows.push(newForm);
    this.addLog(user, 'BORROW', `Gửi yêu cầu mượn ${newId}`);
    this.save();
    return newId;
  }

  // Quy trình mới: Admin duyệt mượn
  approveBorrow(id: string, admin: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && borrow.status === 'Requested') {
      // Kiểm tra kho trước khi duyệt
      for (const item of borrow.items) {
        if (item.type === 'tool') {
          this.checkAndDecrementStock(item.id, item.quantity);
        } else {
          const kit = this.data.kits.find(k => k.id === item.id);
          kit?.items.forEach(ki => this.checkAndDecrementStock(ki.toolId, ki.quantity * item.quantity));
        }
      }

      borrow.status = 'Active';
      borrow.borrowDate = new Date().toISOString();
      borrow.approvedBy = admin.fullName;
      this.addLog(admin, 'APPROVE', `Duyệt mượn phiếu ${id}`);
      this.save();
    }
  }

  private checkAndDecrementStock(toolId: string, qty: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (!tool || tool.availableQuantity < qty) {
      throw new Error(`Dụng cụ ${tool?.name || toolId} không đủ số lượng trong kho`);
    }
    tool.availableQuantity -= qty;
    if (tool.availableQuantity === 0) tool.status = ToolStatus.Borrowed;
  }

  // Quy trình mới: User gửi yêu cầu trả
  requestReturn(id: string, user: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && borrow.status === 'Active') {
      borrow.status = 'ReturnRequested';
      this.addLog(user, 'RETURN', `Gửi yêu cầu trả phiếu ${id}`);
      this.save();
    }
  }

  // Quy trình mới: Admin xác nhận trả
  approveReturn(id: string, admin: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && borrow.status === 'ReturnRequested') {
      // Trả lại kho
      for (const item of borrow.items) {
        if (item.type === 'tool') {
          this.incrementStock(item.id, item.quantity);
        } else {
          const kit = this.data.kits.find(k => k.id === item.id);
          kit?.items.forEach(ki => this.incrementStock(ki.toolId, ki.quantity * item.quantity));
        }
      }
      borrow.status = 'Returned';
      borrow.returnDate = new Date().toISOString();
      this.addLog(admin, 'APPROVE', `Xác nhận hoàn trả phiếu ${id}`);
      this.save();
    }
  }

  private incrementStock(toolId: string, qty: number) {
    const tool = this.data.tools.find(t => t.id === toolId);
    if (tool) {
      tool.availableQuantity += qty;
      tool.status = ToolStatus.Good;
    }
  }

  rejectRequest(id: string, admin: User) {
    const borrow = this.data.borrows.find(b => b.id === id);
    if (borrow && (borrow.status === 'Requested' || borrow.status === 'ReturnRequested')) {
      const oldStatus = borrow.status;
      borrow.status = oldStatus === 'Requested' ? 'Rejected' : 'Active';
      this.addLog(admin, 'REJECT', `Từ chối yêu cầu của phiếu ${id}`);
      this.save();
    }
  }
}

