    link.setAttribute("download", `${filename}_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const pendingCount = useMemo(() => 
    borrows.filter(b => b.status === 'Requested' || b.status === 'ReturnRequested').length, 
  [borrows]);

  const filteredBorrows = useMemo(() => {
    return borrows.filter(b => {
      const matchStatus = borrowFilterStatus === 'All' || b.status === borrowFilterStatus;
      const matchDept = borrowFilterDept === 'All' || b.department === borrowFilterDept;
      const matchSearch = borrowSearch === '' || 
        b.borrower.toLowerCase().includes(borrowSearch.toLowerCase()) ||
        b.id.toLowerCase().includes(borrowSearch.toLowerCase()) ||
        b.items.some(it => it.name.toLowerCase().includes(borrowSearch.toLowerCase()));
      return matchStatus && matchDept && matchSearch;
    }).reverse();
  }, [borrows, borrowFilterStatus, borrowFilterDept, borrowSearch]);

  const getStatusBadge = (status: BorrowStatus) => {
    const styles: Record<BorrowStatus, string> = {
      Requested: 'bg-amber-100 text-amber-700 border-amber-200',
      Active: 'bg-blue-100 text-blue-700 border-blue-200',
      ReturnRequested: 'bg-purple-100 text-purple-700 border-purple-200',
      Returned: 'bg-green-100 text-green-700 border-green-200',
      Rejected: 'bg-red-100 text-red-700 border-red-200'
    };
    const labels: Record<BorrowStatus, string> = {
      Requested: 'Chờ duyệt mượn',
      Active: 'Đang mượn',
      ReturnRequested: 'Chờ xác nhận trả',
      Returned: 'Đã trả',
      Rejected: 'Đã từ chối'
    };
    return (
      <span className={`px-2 py-1 rounded-full text-[10px] font-bold border ${styles[status]}`}>
        {labels[status]}
      </span>
    );
  };

  const renderContent = () => {
    if (currentUser && !ROLE_PERMISSIONS[currentUser.role].includes(activeTab)) {
      return <div className="p-8 text-center text-gray-500">Đang chuyển hướng...</div>;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard tools={tools} borrows={borrows} />;
      case 'tools':
        return (
          <div className="space-y-4">
            <div className="flex justify-end space-x-2">
              <button onClick={() => exportToCSV(tools, 'Danh_sach_dung_cu')} className="px-3 py-1.5 bg-green-50 text-green-700 rounded-lg text-sm font-semibold border border-green-200 hover:bg-green-100">
                Xuất Excel
              </button>
            </div>
            <ToolsList tools={tools} onAddTool={() => { setEditingTool(null); setShowToolModal(true); }} onEditTool={(tool) => { setEditingTool(tool); setShowToolModal(true); }} onAdjustStock={(tool, mode) => { setAdjustingTool(tool); setAdjustMode(mode); setShowAdjustModal(true); }} />
          </div>
        );
      case 'kits':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h3 className="text-xl font-bold">Quản lý Gói Dụng cụ</h3>
              {currentUser?.role === 'admin' && (
                <button onClick={() => { setEditingKit(null); setShowKitModal(true); }} className="px-4 py-1.5 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700">
                  + Thêm gói mới
                </button>
              )}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {kits.map(kit => (
                <div key={kit.id} className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-gray-800">{kit.name}</h3>
                    <span className="text-xs font-mono text-gray-400">{kit.code}</span>
                  </div>
                  <div className="space-y-2 mb-6">
                    {kit.items.map(item => {
                      const tool = tools.find(t => t.id === item.toolId);
                      return <div key={item.toolId} className="flex justify-between text-xs text-gray-600"><span>{tool?.name}</span><span className="font-bold">x{item.quantity}</span></div>
                    })}
                  </div>
                  <button onClick={() => setShowBorrowModal(true)} className="w-full py-2 bg-blue-50 text-blue-600 rounded-lg text-sm font-bold hover:bg-blue-600 hover:text-white transition-colors">Yêu cầu mượn gói này</button>
                </div>
              ))}
            </div>
          </div>
        );
      case 'borrow':
        return (
          <div className="space-y-6">
            {currentUser?.role === 'admin' && pendingCount > 0 && (
              <div className="bg-amber-50 border border-amber-200 p-4 rounded-xl flex items-center justify-between">
                <div className="flex items-center space-x-3 text-amber-800">
                  <div className="w-10 h-10 bg-amber-100 rounded-full flex items-center justify-center">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                  </div>
                  <div>
                    <p className="font-bold">Thông báo phê duyệt</p>
                    <p className="text-sm">Có {pendingCount} yêu cầu đang chờ bạn xử lý.</p>
                  </div>
                </div>
              </div>
            )}

            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <h3 className="text-xl font-bold">Danh sách Mượn/Trả</h3>
              <div className="flex flex-wrap gap-2 w-full md:w-auto">
                <div className="relative flex-1 md:w-64">
                   <input 
                    type="text" 
                    placeholder="Tìm tên người mượn, dụng cụ..." 
                    className="w-full pl-9 pr-4 py-2 border rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500"
                    value={borrowSearch}
                    onChange={(e) => setBorrowSearch(e.target.value)}
                  />
                  <svg className="w-4 h-4 absolute left-3 top-2.5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                </div>
                <select 
                  className="px-3 py-2 border rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500"
                  value={borrowFilterStatus}
                  onChange={(e) => setBorrowFilterStatus(e.target.value)}
                >
                  <option value="All">Tất cả trạng thái</option>
                  <option value="Requested">Chờ duyệt mượn</option>
                  <option value="Active">Đang mượn</option>
                  <option value="ReturnRequested">Chờ xác nhận trả</option>
                  <option value="Returned">Đã trả</option>
                  <option value="Rejected">Đã từ chối</option>
                </select>
                <select 
                  className="px-3 py-2 border rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500"
                  value={borrowFilterDept}
                  onChange={(e) => setBorrowFilterDept(e.target.value)}
                >
                  <option value="All">Tất cả khoa phòng</option>
                  {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
                <button onClick={() => setShowBorrowModal(true)} className="px-4 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200">+ Gửi yêu cầu mượn</button>
              </div>
            </div>

            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-gray-50 text-gray-500 text-[10px] font-bold uppercase">
                    <tr>
                      <th className="px-6 py-4">Mã / Ngày yêu cầu</th>
                      <th className="px-6 py-4">Người mượn / Khoa</th>
                      <th className="px-6 py-4">Dụng cụ</th>
                      <th className="px-6 py-4">Trạng thái</th>
                      <th className="px-6 py-4">Hành động</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-100">
                    {filteredBorrows.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="px-6 py-12 text-center text-gray-400">Không tìm thấy phiếu mượn nào phù hợp bộ lọc.</td>
                      </tr>
                    ) : (
                      filteredBorrows.map(b => (
                        <tr key={b.id} className="hover:bg-gray-50/50">
                          <td className="px-6 py-4">
                            <p className="font-bold text-blue-600">{b.id}</p>
                            <p className="text-[10px] text-gray-400">{new Date(b.requestDate).toLocaleDateString('vi-VN')}</p>
                          </td>
                          <td className="px-6 py-4">
                            <p className="font-semibold text-gray-800">{b.borrower}</p>
                            <p className="text-xs text-gray-500">{b.department}</p>
                          </td>
                          <td className="px-6 py-4">
                            <div className="text-[10px] space-y-0.5">
                              {b.items.map((it, i) => <div key={i} className="text-gray-600">• {it.name} (x{it.quantity})</div>)}
                            </div>
                          </td>
                          <td className="px-6 py-4">{getStatusBadge(b.status)}</td>
                          <td className="px-6 py-4">
                            <div className="flex space-x-2">
                              {currentUser?.role === 'admin' && b.status === 'Requested' && (
                                <>
                                  <button onClick={() => handleApproveBorrow(b.id)} className="px-3 py-1 bg-green-600 text-white text-[10px] font-bold rounded hover:bg-green-700 whitespace-nowrap">Duyệt mượn</button>
                                  <button onClick={() => handleRejectRequest(b.id)} className="px-3 py-1 bg-red-50 text-red-600 text-[10px] font-bold rounded hover:bg-red-100">Từ chối</button>
                                </>
                              )}
                              {currentUser?.role === 'admin' && b.status === 'ReturnRequested' && (
                                <>
                                  <button onClick={() => handleApproveReturn(b.id)} className="px-3 py-1 bg-purple-600 text-white text-[10px] font-bold rounded hover:bg-purple-700 whitespace-nowrap">Xác nhận đã trả</button>
                                  <button onClick={() => handleRejectRequest(b.id)} className="px-3 py-1 bg-gray-100 text-gray-600 text-[10px] font-bold rounded hover:bg-gray-200">Báo lỗi</button>
                                </>
                              )}
                              {b.status === 'Active' && (
                                <button onClick={() => handleRequestReturn(b.id)} className="px-3 py-1 bg-blue-50 text-blue-600 text-[10px] font-bold rounded hover:bg-blue-100 border border-blue-200 whitespace-nowrap">Yêu cầu trả</button>
                              )}
                            </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );
      case 'history':
        return (
          <div className="space-y-4">
            <h3 className="text-xl font-bold">Nhật ký audit hệ thống</h3>
            <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
               <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 text-gray-500 text-[10px] font-bold uppercase">
                  <tr><th className="px-6 py-4">Thời gian</th><th className="px-6 py-4">Người dùng</th><th className="px-6 py-4">Hành động</th><th className="px-6 py-4">Chi tiết</th></tr>
                </thead>
                <tbody className="divide-y divide-gray-100 text-xs">
                  {logs.map(log => (
                    <tr key={log.id}>
                      <td className="px-6 py-4 text-gray-400">{new Date(log.timestamp).toLocaleString('vi-VN')}</td>
                      <td className="px-6 py-4 font-bold">{log.userName}</td>
                      <td className="px-6 py-4"><span className="px-2 py-0.5 bg-gray-100 rounded text-[9px] font-black">{log.action}</span></td>
                      <td className="px-6 py-4 text-gray-600">{log.details}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        );
      case 'reports':
        return (
          <div className="space-y-6">
            <div className="bg-white p-8 rounded-2xl border border-blue-100 shadow-xl shadow-blue-50">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center space-x-3">
                  <div className="w-2 h-8 bg-blue-600 rounded-full"></div>
                  <h3 className="text-2xl font-black text-gray-900">AI Inventory Insights</h3>
                </div>
                <button onClick={() => {}} className="text-blue-600 hover:text-blue-800 text-sm font-bold flex items-center space-x-2 bg-blue-50 px-4 py-2 rounded-xl transition-colors">
                   <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                   <span>Refersh</span>
                </button>
              </div>
              <div className="prose max-w-none text-gray-700 whitespace-pre-line leading-relaxed bg-blue-50/30 p-8 rounded-2xl border border-blue-100 italic">
                {insights || "Dữ liệu AI đang được xử lý hoặc chưa được khởi tạo..."}
              </div>
            </div>
          </div>
        );
      default: return <div className="p-8 text-center text-gray-500">Nội dung không khả dụng.</div>;
    }
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} user={currentUser} onLogout={handleLogout}>
      {renderContent()}
      {showBorrowModal && currentUser && (
        <BorrowModal tools={tools} kits={kits} currentUser={currentUser} onClose={() => setShowBorrowModal(false)} onSave={handleRequestBorrow} />
      )}
      {showToolModal && (
        <ToolFormModal tool={editingTool} onClose={() => { setShowToolModal(false); setEditingTool(null); }} onSave={(tool) => { db.upsertTool(tool, currentUser!); refreshData(); setShowToolModal(false); }} />
      )}
      {showKitModal && (
        <KitFormModal kit={editingKit} tools={tools} onClose={() => { setShowKitModal(false); setEditingKit(null); }} onSave={(kit) => { db.upsertKit(kit, currentUser!); refreshData(); setShowKitModal(false); }} />
      )}
      {showAdjustModal && adjustingTool && (
        <QuantityAdjustmentModal tool={adjustingTool} mode={adjustMode} onClose={() => setShowAdjustModal(false)} onConfirm={(amount) => { try { db.adjustStock(adjustingTool.id, amount, currentUser!); refreshData(); setShowAdjustModal(false); } catch(e:any){alert(e.message)} }} />
      )}
    </Layout>
  );
};

export default App;
